document.addEventListener('DOMContentLoaded', function () {
  if (document.body) {
    document.body.setAttribute('dir', document.documentElement.getAttribute('dir') || 'ltr');
  }
});

document.addEventListener('DOMContentLoaded', () => {
  const sectionHero = document.getElementById('hero');
  const sectionCta = document.getElementById('cta');

  if (!sectionHero && !sectionCta) return;

  function updateTheme() {
    const heroRect = sectionHero?.getBoundingClientRect();
    const ctaRect = sectionCta?.getBoundingClientRect();
    const viewportHeight = window.innerHeight;

    if (ctaRect && ctaRect.top < viewportHeight * 0.4) {
      document.documentElement.setAttribute('data-theme', 'dark');
      return;
    }

    if (heroRect && heroRect.bottom > viewportHeight * 0.2) {
      document.documentElement.setAttribute('data-theme', 'dark');
      return;
    }

    document.documentElement.setAttribute('data-theme', 'light');
  }

  updateTheme();
  window.addEventListener('scroll', updateTheme, { passive: true });
});

