/* ─── Тематические настройки ─── */
:root[data-theme="dark"] {
  --res-shadow: 0 20px 40px rgba(0, 0, 0, 0.4);
  --res-item-hover: rgba(255, 255, 255, 0.05);
  --res-icon-bg: rgba(255, 255, 255, 0.03);
  --res-desc: rgba(255, 255, 255, 0.5);
}

:root[data-theme="light"] {
  --res-shadow: 0 15px 30px rgba(0, 0, 0, 0.08);
  --res-item-hover: rgba(0, 0, 0, 0.03);
  --res-icon-bg: rgba(0, 0, 0, 0.02);
  --res-desc: var(--color-gray-second);
}

.header-menu {
  margin-left: auto;
  margin-right: 30px;
}

.header-menu-list {
  display: flex;
  column-gap: 3.9375rem;
}

.header-menu-item {
  position: relative;
}

/* Свечение при ховере */
.header-menu-item::after {
  content: "";
  position: absolute;
  bottom: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 100%;
  height: 100%;
  background-image: var(--menu-item-bg, none);
  background-repeat: no-repeat;
  background-position: center bottom;
  background-size: contain;
  opacity: 0;
  transition: opacity var(--transition-duration) cubic-bezier(0.34, 1.56, 0.64, 1);
  pointer-events: none;
  z-index: 1;
}

.header-menu-item:hover::after {
  opacity: 1;
}

.header-menu-link, .resources-trigger {
  display: inline-flex;
  align-items: center;
  padding-inline: 0.625rem;
  height: var(--header-height);
  font-size: 1.25rem;
  color: var(--color-heading);
  transition: color var(--transition-duration) ease;
}

.resources-dropdown-wrapper {
  display: flex;
  align-items: center;
}

.resources-trigger {
  background: none;
  border: none;
  font-family: inherit;
  cursor: pointer;
  gap: 8px;
}

.resources-chevron {
  transition: transform 0.25s ease;
}

.resources-dropdown-wrapper.is-open .resources-chevron {
  transform: rotate(180deg);
}

.resources-menu-dropdown {
  position: absolute;
  top: 100%;
  left: 50%;
  transform: translateX(-50%) translateY(10px);
  min-width: 580px;
  background-color: var(--locale-selector-bg);
  border-radius: 1.25rem;
  padding: 1.5rem;
  box-shadow: var(--res-shadow);
  border: 1px solid var(--card-border);
  opacity: 0;
  visibility: hidden;
  pointer-events: none;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  z-index: 1000;
}

.resources-menu-dropdown::before {
  content: "";
  position: absolute;
  top: -20px;
  left: 0;
  right: 0;
  height: 25px;
}

.resources-dropdown-wrapper.is-open .resources-menu-dropdown {
  opacity: 1;
  visibility: visible;
  pointer-events: auto;
  transform: translateX(-50%) translateY(0);
}

.resources-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
}

.resource-item {
  display: flex;
  align-items: flex-start;
  gap: 1rem;
  padding: 0.875rem;
  border-radius: 0.75rem;
  text-decoration: none;
  transition: background-color 0.2s ease;
}

.resource-item:hover {
  background-color: var(--res-item-hover);
}

.resource-icon {
  flex-shrink: 0;
  width: 40px;
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--res-icon-bg);
  border: 1px solid var(--card-border);
  border-radius: 10px;
  color: #6BC0F9;
}

.resource-info {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.resource-title {
  color: var(--color-heading);
  font-size: 1rem;
  font-weight: 500;
}

.resource-desc {
  color: var(--res-desc);
  font-size: 0.8125rem;
  line-height: 1.4;
}

/* Media Queries */
@media (width < 120rem) {
  .header-menu-list { column-gap: 1.5625rem; }
  .header-menu-link, .resources-trigger { font-size: 1rem; }
}

@media (width < 90rem) {
  .header-menu { margin-inline: 0; }
  .header-menu-list { column-gap: 1rem; }
  .header-menu-link, .resources-trigger { font-size: 0.875rem; }
  .resources-menu-dropdown { min-width: 500px; }
}

@media (width < 80rem) {
  .header-menu { display: none; }
}

