.locale-selector {
  position: relative;
  display: inline-block;
  line-height: 1.35;
  letter-spacing: -0.01em;
  z-index: 100;
  isolation: isolate;
}

.locale-trigger {
  display: inline-flex;
  align-items: center;
  justify-content: space-between;
  gap: 6px;
  padding-inline: 15px;
  height: 42px;
  border: none;
  border-radius: 10px;
  background-color: var(--header-bg);
  color: var(--color-heading);
  font-size: 1rem;
  font-weight: 400;
  letter-spacing: -0.01em;
  cursor: pointer;
  white-space: nowrap;
  position: relative;
  min-width: 180px;
  transition: border-radius 0.2s ease;
}

.locale-trigger-left {
  display: flex;
  align-items: center;
  gap: 6px;
}

/* Эффект открытого меню для кнопки */
.locale-selector.is-open .locale-trigger {
  border-bottom-left-radius: 0;
  border-bottom-right-radius: 0;
}

.locale-selector.is-open .locale-chevron {
  transform: rotate(180deg);
}

.locale-chevron {
  flex-shrink: 0;
  transition: transform var(--transition-duration) cubic-bezier(0.4, 0, 0.2, 1);
}

.locale-dropdown {
  position: absolute;
  top: 100%; /* Прижимаем к низу триггера */
  left: 0;
  min-width: 100%;
  background-color: var(--locale-selector-bg);
  border-bottom-right-radius: 1.25rem;
  border-bottom-left-radius: 1.25rem;
  overflow: hidden;
  z-index: 9999;
  opacity: 0;
  visibility: hidden;
  pointer-events: none;
  transform: translateY(10px); /* Начальное смещение как у Resources */
  transition:
    opacity 0.25s cubic-bezier(0.4, 0, 0.2, 1),
    transform 0.25s cubic-bezier(0.4, 0, 0.2, 1),
    visibility 0.25s;
}

/* Невидимый мостик, чтобы меню не закрывалось при движении мыши вниз */
.locale-dropdown::before {
  content: "";
  position: absolute;
  top: -20px;
  left: 0;
  right: 0;
  height: 25px;
  background: transparent;
}

.locale-selector.is-open .locale-dropdown {
  opacity: 1;
  visibility: visible;
  pointer-events: auto;
  transform: translateY(0);
}

.locale-list {
  list-style: none;
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: 0.125rem;
  max-height: 304px;
  overflow-y: auto;
  padding: 0;
}

.locale-item {
  display: flex;
  align-items: center;
  gap: 0.625rem;
  padding: 0.625rem 0.875rem;
  color: var(--color-heading);
  font-size: 1rem;
  font-weight: 400;
  cursor: pointer;
  white-space: nowrap;
  position: relative;
  opacity: 0;
  transform: translateX(-4px);
  transition: opacity 0.2s ease,
              transform 0.2s ease,
              background-color var(--transition-duration) ease;
}

.locale-selector.is-open .locale-item {
  opacity: 1;
  transform: translateX(0);
}

/* Твои задержки анимации */
.locale-selector.is-open .locale-item:nth-child(1) { transition-delay: 0.04s; }
.locale-selector.is-open .locale-item:nth-child(2) { transition-delay: 0.07s; }
.locale-selector.is-open .locale-item:nth-child(3) { transition-delay: 0.10s; }
.locale-selector.is-open .locale-item:nth-child(4) { transition-delay: 0.13s; }
.locale-selector.is-open .locale-item:nth-child(5) { transition-delay: 0.16s; }
.locale-selector.is-open .locale-item:nth-child(6) { transition-delay: 0.19s; }

.locale-item:hover {
  background-color: rgba(255, 255, 255, 0.06);
}

.locale-item.is-active {
  background-color: rgba(107, 192, 249, 0.1);
}

.locale-item-label {
  font-size: 1rem;
  flex: 1;
}

.locale-check {
  width: 0.875rem;
  height: 0.875rem;
  flex-shrink: 0;
  color: #6BC0F9;
  opacity: 0;
  transform: scale(0.6);
  transition:
    opacity 0.2s ease,
    transform 0.2s cubic-bezier(0.34, 1.56, 0.64, 1);
}

.locale-item.is-active .locale-check {
  opacity: 1;
  transform: scale(1);
}

.flag-icon {
  width: 20px !important;
  height: 12px !important;
  flex-shrink: 0;
}

@media (width < 90rem) {
  .locale-trigger { font-size: 12px; }
  .locale-item-label { font-size: 12px; }
}

@media (width < 80rem) {
  .locale-selector { display: none; }
}

