document.addEventListener('DOMContentLoaded', () => {
  const heroCardContainer = document.querySelectorAll('.hero-card');

  heroCardContainer.forEach(container => {
    const players = container.querySelectorAll('lottie-player');

    container.addEventListener('mouseenter', () => {
      players.forEach(player => {
        if (player.offsetParent !== null && typeof player.play === 'function') {
          player.setDirection(1);
          player.seek(20); 
          player.play();
        }
      });
    });

    container.addEventListener('mouseleave', () => {
      players.forEach(player => {
        if (player.offsetParent !== null && typeof player.play === 'function') {
          player.setDirection(-1);
          player.play();
        }
      });
    });
  });
});

