document.addEventListener('DOMContentLoaded', () => {
  const tools = document.querySelector('.tools');

  if (tools) {
    const bg = tools.getAttribute('data-bg');

    if (bg) {
      const observer = new IntersectionObserver(
        (entries) => {
          entries.forEach((entry) => {
            if (!entry.isIntersecting) return;
            tools.style.setProperty('--tools-bg', 'url("' + bg + '")');
            observer.unobserve(tools);
          });
        },
        { rootMargin: '200px', threshold: 0 }
      );

      observer.observe(tools);
    }
  }
});

function toggleTableFAQ(button) {
  const faqItem = button.closest(".tools-faq-item");
  const firstItem = document.querySelector(".tools-faq-item");

  if (faqItem === firstItem) return;

  const answer = faqItem.querySelector(".tools-faq-answer");
  const allItems = document.querySelectorAll(".tools-faq-item");

  allItems.forEach((item) => {
    if (item !== faqItem && item !== firstItem && item.classList.contains("active")) {
      item.classList.remove("active");
      const otherAnswer = item.querySelector(".tools-faq-answer");
      otherAnswer.style.maxHeight = "0";
    }
  });

  if (faqItem.classList.contains("active")) {
    faqItem.classList.remove("active");
    answer.style.maxHeight = "0";
  } else {
    faqItem.classList.add("active");
    answer.style.maxHeight = answer.scrollHeight + "px";
  }
}

function setStickyColumns() {
    const table = document.querySelector('.tools-table');
    if (!table) return;
    const firstTh = table.querySelector('thead th:first-child');
    if (!firstTh) return;
    const firstColWidth = firstTh.getBoundingClientRect().width;
    if (firstColWidth === 0) return;
    table.querySelectorAll('thead th:nth-child(2), tbody td:nth-child(2)').forEach(el => {
        el.style.left = firstColWidth + 'px';
    });
}

function positionSWFrame() {
    const wrapper   = document.querySelector('.tools-table-wrapper');
    const container = document.querySelector('.tools-container');
    const table     = document.querySelector('.tools-table');
    if (!container || !table || !wrapper) return;
    const thCell     = table.querySelector('thead th:nth-child(2)');
    const lastTdCell = table.querySelector('tbody tr:last-child td:nth-child(2)');
    if (!thCell || !lastTdCell) return;
    const containerRect = container.getBoundingClientRect();
    const thRect        = thCell.getBoundingClientRect();
    const lastTdRect    = lastTdCell.getBoundingClientRect();
    const left   = thRect.left   - containerRect.left;
    const top    = thRect.top    - containerRect.top;
    const width  = thRect.width;
    const height = lastTdRect.bottom - thRect.top;
    let frame = container.querySelector('.sw-col-frame');
    if (!frame) {
        frame = document.createElement('div');
        frame.className = 'sw-col-frame';
        container.appendChild(frame);
    }
    frame.style.left   = left   + 'px';
    frame.style.top    = top    + 'px';
    frame.style.width  = width  + 'px';
    frame.style.height = height + 'px';
}

document.addEventListener('DOMContentLoaded', () => {
    setStickyColumns();
    positionSWFrame();
    const wrapper = document.querySelector('.tools-table-wrapper');
    if (wrapper) wrapper.addEventListener('scroll', positionSWFrame);
});

window.addEventListener('resize', () => {
    setStickyColumns();
    positionSWFrame();
});

