document.addEventListener('DOMContentLoaded', () => {
  const ecosystemInner = document.querySelector('.ecosystem-inner');
  const ecosystemButton = document.querySelector('.ecosystem-button');

  if (ecosystemInner) {
    const bg = ecosystemInner.getAttribute('data-bg');

    if (bg) {
      const observer = new IntersectionObserver(
        (entries) => {
          entries.forEach((entry) => {
            if (!entry.isIntersecting) return;
            ecosystemInner.style.setProperty('--eco-bg', 'url("' + bg + '")');
            observer.unobserve(ecosystemInner);
          });
        },
        { rootMargin: '200px', threshold: 0 }
      );

      observer.observe(ecosystemInner);
    }
  }

  ecosystemButton?.addEventListener('mouseenter', () => {
    ecosystemInner?.classList.add('is-hovered');
  });
  ecosystemButton?.addEventListener('mouseleave', () => {
    ecosystemInner?.classList.remove('is-hovered');
  });
});

