document.addEventListener('DOMContentLoaded', () => {
  // Observer для foundation-card
  const foundationCards = document.querySelectorAll('.foundation-card');

  if (foundationCards.length) {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add('is-visible');
            observer.unobserve(entry.target);
          }
        });
      },
      {
        threshold: 0.1,
        rootMargin: '0px 0px -40px 0px',
      }
    );

    foundationCards.forEach((card) => observer.observe(card));
  }
});

// Функцию оставляем снаружи, если она используется в HTML (onclick и т.п.)
function toggleCardAccordion(button) {
  const accordionItem = button.closest('.card-accordion-item');
  const content = accordionItem.querySelector('.card-accordion-content');
  const icon = button.querySelector('.card-accordion-icon');
  const isOpen = content.style.maxHeight && content.style.maxHeight !== '0px';

  if (isOpen) {
    content.style.maxHeight = '0px';
    icon.style.transform = 'rotate(0deg)';
  } else {
    content.style.maxHeight = content.scrollHeight + 'px';
    icon.style.transform = 'rotate(180deg)';
  }
}

