document.addEventListener('mouseenter', function(e) {
  if (!e.target || typeof e.target.closest !== 'function') return;
  const partnerCard = e.target.closest('.partner-card');
  if (!partnerCard || partnerCard.dataset.bgLoaded) return;
  partnerCard.dataset.bgLoaded = 'true';
  const btn = partnerCard.querySelector('.partner-button');
  if (btn) btn.style.setProperty('--partner-btn-bg', 'url("/core/image/${PARTNER_BUTTON_SHADOW@IMAGE}/get")');
}, true);

document.addEventListener('DOMContentLoaded', () => {
  document.querySelectorAll('feGaussianBlur').forEach(f => {
    const val = parseFloat(f.getAttribute('stdDeviation'));
    if (val > 30) {
      // Снижаем до максимум 24, сохраняем пропорцию
      f.setAttribute('stdDeviation', Math.min(val * 0.3, 24));
    }
  });

  document.querySelectorAll('.partner-card').forEach(card => {
    // Собираем элементы
    const targets = {
      svg: card.querySelector('.partner-svg'),
      head: card.querySelector('.svg-head'),
      body: card.querySelector('.svg-body'),
      ball: card.querySelector('.svg-ball'),
      icons: card.querySelector('.svg-icons'),
      btn: card.querySelector('.card-btn')
    };

    const tl = gsap.timeline({ paused: true });

    // Добавляем в анимацию только те элементы, которые реально найдены
    if (targets.svg) {
      tl.to(targets.svg, { y: 5, duration: 0.4, ease: 'power2.out' }, 0);
    }
    if (targets.head) {
      tl.to(targets.head, { scale: 0.9, transformOrigin: 'center center', duration: 0.4, ease: 'power2.inOut' }, 0);
    }
    if (targets.body) {
      tl.to(targets.body, { y: -10, scale: 0.9, transformOrigin: 'center center', duration: 0.4, ease: 'power2.inOut' }, 0);
    }
    if (targets.ball) {
      tl.to(targets.ball, { scale: 1.1, transformOrigin: 'center center', duration: 0.4, ease: 'back.out(2)' }, 0);
    }
    if (targets.icons) {
      tl.to(targets.icons, { scale: 1.1, transformOrigin: 'center center', duration: 0.4, ease: 'back.out(2)' }, 0);
    }
    if (targets.btn) {
      tl.to(targets.btn, { opacity: 1, y: 0, duration: 0.3, ease: 'power2.out' }, 0.1);
    }

    card.addEventListener('mouseenter', () => {
      card.style.willChange = 'transform';
      tl.play()
    });
    card.addEventListener('mouseleave', () => {
      tl.reverse()
      tl.eventCallback('onReverseComplete', () => {
        card.style.willChange = 'auto';
      });
    });
  });
});

