document.addEventListener('mouseenter', function(e) {
  if (!e.target || typeof e.target.closest !== 'function') return;
  const item = e.target.closest('.faq-item');
  if (!item || item.dataset.bgLoaded) return;
  item.dataset.bgLoaded = 'true';
  item.style.setProperty('--faq-bg', 'url("/core/image/${FAQ_ITEM_SHADOW@IMAGE}/get")');
}, true);

function toggleFAQ(button) {
  const faqItem = button.closest(".faq-item");

  if (!faqItem) return;

  const answer = faqItem.querySelector(".faq-answer");
  const allItems = document.querySelectorAll(".faq-item");

  allItems.forEach((item) => {
    if (item !== faqItem && item.classList.contains("active")) {
      item.classList.remove("active");
      const otherAnswer = item.querySelector(".faq-answer");
      otherAnswer.style.maxHeight = "0";
    }
  });

  if (faqItem.classList.contains("active")) {
    faqItem.classList.remove("active");
    answer.style.maxHeight = "0";
  } else {
    faqItem.classList.add("active");
    answer.style.maxHeight = answer.scrollHeight + "px";
  }
}

document.addEventListener('DOMContentLoaded', () => {
   const container = document.querySelector('.faq-list');
  if (!container) return;

  const items = Array.from(container.children);

  items.sort((a, b) => {
    const orderA = parseInt(a.getAttribute('data-order')) || 0;
    const orderB = parseInt(b.getAttribute('data-order')) || 0;
    return orderA - orderB;
  });

  items.forEach(item => container.appendChild(item));
})

