children.javascript:
document.addEventListener('DOMContentLoaded', () => {
  if (document.startViewTransition && !window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
    document.startViewTransition(() => {
      document.documentElement.setAttribute('data-theme', 'dark');
    });
  } else {
    document.documentElement.setAttribute('data-theme', 'dark');
  }

  const code = new URLSearchParams(window.location.search).get('code');
  if (!code) return;

  const container = document.getElementById("form-container");
  const lang = document.documentElement.getAttribute('lang');

  new DynamicForm({
    type: '${PARTNER_FORM_PRESENTATION}',
    apiBaseUrl: window.location.origin,
    organizationId: ${PARTNER_ORGANIZAITON_ID@INTEGER},
     formTypeCode: '${PARTNER_FORM_TYPE_CODE}',
    lang,
    submitLabel: stripTags('${PARTNER_SUBMIT_LABEL@LOCALIZED_STRING_SS}'),
     presetValues: {
      PARTNER_TYPE: code,
    },
    onSubmit: function (data) {
      const params = new URLSearchParams(window.location.search);
      params.delete('code');
      const basePath = window.location.pathname.replace('partner.html', 'success.html');
      window.location.href = basePath + '?' + params.toString();
    },
    withLabel: true
  }).mount("#form-container");
});

